package value

import (
	"bytes"
	"context"
	"fmt"
	"testing"

	genericapirequest "k8s.io/apiserver/pkg/endpoints/request"
)

// mockTransformer is a simple Transformer implementation for testing.
// It returns configurable outputs and records what it received.
type mockTransformer struct {
	fromResult    []byte
	fromStale     bool
	fromErr       error
	toResult      []byte
	toErr         error
	lastFromInput []byte
	lastToInput   []byte
}

func (m *mockTransformer) TransformFromStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
	m.lastFromInput = data
	return m.fromResult, m.fromStale, m.fromErr
}

func (m *mockTransformer) TransformToStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
	m.lastToInput = data
	return m.toResult, m.toErr
}

// identityTransformer passes data through without modification.
type identityTransformer struct{}

func (identityTransformer) TransformFromStorage(_ context.Context, data []byte, _ Context) ([]byte, bool, error) {
	return data, false, nil
}

func (identityTransformer) TransformToStorage(_ context.Context, data []byte, _ Context) ([]byte, error) {
	return data, nil
}

func testReqCtx() context.Context {
	return genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "secrets"})
}

// TestDefaultContext verifies that DefaultContext.AuthenticatedData returns the underlying bytes.
func TestDefaultContext(t *testing.T) {
	cases := []struct {
		name  string
		input DefaultContext
		want  []byte
	}{
		{name: "nil context", input: nil, want: nil},
		{name: "empty context", input: DefaultContext{}, want: DefaultContext{}},
		{name: "non-empty context", input: DefaultContext("mykey/v1/resource"), want: []byte("mykey/v1/resource")},
		{name: "binary data", input: DefaultContext{0x00, 0xff, 0xab}, want: []byte{0x00, 0xff, 0xab}},
	}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			got := tc.input.AuthenticatedData()
			if !bytes.Equal(got, tc.want) {
				t.Errorf("AuthenticatedData() = %v, want %v", got, tc.want)
			}
		})
	}
}

// TestTransformerRoundTrip verifies that data written by TransformToStorage can be
// recovered by TransformFromStorage using a PrefixTransformer wrapping an identity transformer.
func TestTransformerRoundTrip(t *testing.T) {
	cases := []struct {
		name    string
		prefix  string
		payload []byte
	}{
		{name: "simple ascii", prefix: "k8s:enc:aescbc:v1:", payload: []byte("hello, world")},
		{name: "empty payload", prefix: "k8s:enc:aescbc:v1:", payload: []byte{}},
		{name: "binary payload", prefix: "enc:", payload: []byte{0x00, 0x01, 0x02, 0xff}},
		{name: "large payload", prefix: "pfx:", payload: bytes.Repeat([]byte("a"), 4096)},
	}

	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			pt := NewPrefixTransformers(
				fmt.Errorf("no match"),
				PrefixTransformer{
					Prefix:      []byte(tc.prefix),
					Transformer: identityTransformer{},
				},
			)
			ctx := testReqCtx()

			encrypted, err := pt.TransformToStorage(ctx, tc.payload, nil)
			if err != nil {
				t.Fatalf("TransformToStorage() unexpected error: %v", err)
			}

			// Verify the prefix is prepended.
			if !bytes.HasPrefix(encrypted, []byte(tc.prefix)) {
				t.Errorf("TransformToStorage() result %q does not start with prefix %q", encrypted, tc.prefix)
			}

			decrypted, stale, err := pt.TransformFromStorage(ctx, encrypted, nil)
			if err != nil {
				t.Fatalf("TransformFromStorage() unexpected error: %v", err)
			}
			if stale {
				t.Errorf("TransformFromStorage() stale = true, want false for primary transformer")
			}
			if !bytes.Equal(decrypted, tc.payload) {
				t.Errorf("round-trip mismatch: got %q, want %q", decrypted, tc.payload)
			}
		})
	}
}

// TestPrefixTransformerMismatch verifies that when no prefix matches, the default error is returned.
func TestPrefixTransformerMismatch(t *testing.T) {
	defaultErr := fmt.Errorf("no transformer matched")
	pt := NewPrefixTransformers(
		defaultErr,
		PrefixTransformer{Prefix: []byte("k8s:enc:aes:"), Transformer: identityTransformer{}},
		PrefixTransformer{Prefix: []byte("k8s:enc:kms:"), Transformer: identityTransformer{}},
	)
	ctx := testReqCtx()

	// Data with a completely different prefix should not match.
	_, _, err := pt.TransformFromStorage(ctx, []byte("unknown:somedata"), nil)
	if err == nil {
		t.Fatal("TransformFromStorage() expected an error for mismatched prefix, got nil")
	}
	if err != defaultErr {
		t.Errorf("TransformFromStorage() error = %v, want %v", err, defaultErr)
	}
}

// TestPrefixTransformerStaleOnNonPrimary verifies the stale flag is set to true when data
// is decoded by a non-primary (non-first) transformer, indicating a re-write should occur.
func TestPrefixTransformerStaleOnNonPrimary(t *testing.T) {
	primary := &mockTransformer{fromResult: []byte("plain"), fromStale: false}
	secondary := &mockTransformer{fromResult: []byte("plain"), fromStale: false}

	pt := NewPrefixTransformers(
		fmt.Errorf("no match"),
		PrefixTransformer{Prefix: []byte("new:"), Transformer: primary},
		PrefixTransformer{Prefix: []byte("old:"), Transformer: secondary},
	)
	ctx := testReqCtx()

	// Data prefixed with "old:" matches the second transformer.
	_, stale, err := pt.TransformFromStorage(ctx, []byte("old:somedata"), nil)
	if err != nil {
		t.Fatalf("TransformFromStorage() unexpected error: %v", err)
	}
	if !stale {
		t.Error("TransformFromStorage() stale = false, want true when non-primary transformer is used")
	}

	// Data prefixed with "new:" matches the primary transformer; stale should reflect the transformer's own value.
	_, stale, err = pt.TransformFromStorage(ctx, []byte("new:somedata"), nil)
	if err != nil {
		t.Fatalf("TransformFromStorage() unexpected error: %v", err)
	}
	if stale {
		t.Error("TransformFromStorage() stale = true, want false when primary transformer is used")
	}
}

// TestPrefixTransformerStaleFromInnerTransformer verifies that stale=true from an inner
// transformer is propagated even when using the primary position.
func TestPrefixTransformerStaleFromInnerTransformer(t *testing.T) {
	staleTransformer := &mockTransformer{fromResult: []byte("value"), fromStale: true}
	pt := NewPrefixTransformers(
		fmt.Errorf("no match"),
		PrefixTransformer{Prefix: []byte("pfx:"), Transformer: staleTransformer},
	)
	ctx := testReqCtx()

	_, stale, err := pt.TransformFromStorage(ctx, []byte("pfx:somedata"), nil)
	if err != nil {
		t.Fatalf("TransformFromStorage() unexpected error: %v", err)
	}
	if !stale {
		t.Error("TransformFromStorage() stale = false, want true because inner transformer reported stale")
	}
}

// TestPrefixTransformerEmptyPrefixIdentity verifies that an empty prefix acts as an
// identity transformer (matches any data) and passes data through unmodified.
func TestPrefixTransformerEmptyPrefixIdentity(t *testing.T) {
	innerResult := []byte("decoded")
	inner := &mockTransformer{fromResult: innerResult}
	pt := NewPrefixTransformers(
		fmt.Errorf("no match"),
		PrefixTransformer{Prefix: []byte{}, Transformer: inner},
	)
	ctx := testReqCtx()

	rawData := []byte("anything at all")
	got, _, err := pt.TransformFromStorage(ctx, rawData, nil)
	if err != nil {
		t.Fatalf("TransformFromStorage() unexpected error: %v", err)
	}
	if !bytes.Equal(got, innerResult) {
		t.Errorf("TransformFromStorage() = %q, want %q", got, innerResult)
	}
	// The inner transformer should receive the full data (no prefix stripped when prefix is empty).
	if !bytes.Equal(inner.lastFromInput, rawData) {
		t.Errorf("inner transformer received %q, want %q", inner.lastFromInput, rawData)
	}
}

// TestPrefixTransformerWriteUsesFirstTransformer verifies TransformToStorage always uses
// the first (primary) transformer and prepends its prefix.
func TestPrefixTransformerWriteUsesFirstTransformer(t *testing.T) {
	first := &mockTransformer{toResult: []byte("encrypted")}
	second := &mockTransformer{toResult: []byte("should-not-be-used")}

	pt := NewPrefixTransformers(
		fmt.Errorf("no match"),
		PrefixTransformer{Prefix: []byte("k8s:enc:aes:v1:"), Transformer: first},
		PrefixTransformer{Prefix: []byte("k8s:enc:kms:v1:"), Transformer: second},
	)
	ctx := testReqCtx()

	plaintext := []byte("secret data")
	got, err := pt.TransformToStorage(ctx, plaintext, nil)
	if err != nil {
		t.Fatalf("TransformToStorage() unexpected error: %v", err)
	}

	want := append([]byte("k8s:enc:aes:v1:"), []byte("encrypted")...)
	if !bytes.Equal(got, want) {
		t.Errorf("TransformToStorage() = %q, want %q", got, want)
	}
	if second.lastToInput != nil {
		t.Error("TransformToStorage() invoked secondary transformer, expected only primary")
	}
	if !bytes.Equal(first.lastToInput, plaintext) {
		t.Errorf("primary transformer received %q, want %q", first.lastToInput, plaintext)
	}
}

// TestPrefixTransformerWriteError verifies that errors from TransformToStorage are propagated.
func TestPrefixTransformerWriteError(t *testing.T) {
	writeErr := fmt.Errorf("encryption key unavailable")
	pt := NewPrefixTransformers(
		fmt.Errorf("no match"),
		PrefixTransformer{
			Prefix:      []byte("k8s:enc:"),
			Transformer: &mockTransformer{toErr: writeErr},
		},
	)
	ctx := testReqCtx()

	_, err := pt.TransformToStorage(ctx, []byte("data"), nil)
	if err == nil {
		t.Fatal("TransformToStorage() expected error, got nil")
	}
	if err != writeErr {
		t.Errorf("TransformToStorage() error = %v, want %v", err, writeErr)
	}
}

// TestNewPrefixTransformersDefaultError verifies that when nil is passed as the error to
// NewPrefixTransformers, a non-nil default error is used for unmatched prefixes.
func TestNewPrefixTransformersDefaultError(t *testing.T) {
	pt := NewPrefixTransformers(
		nil, // pass nil; implementation should supply a default error
		PrefixTransformer{Prefix: []byte("pfx:"), Transformer: identityTransformer{}},
	)
	ctx := testReqCtx()

	_, _, err := pt.TransformFromStorage(ctx, []byte("nomatch:data"), nil)
	if err == nil {
		t.Fatal("TransformFromStorage() expected a non-nil error for unmatched prefix, got nil")
	}
}

// TestPrefixTransformerReadError verifies that errors from the inner transformer's
// TransformFromStorage are propagated correctly to the caller.
func TestPrefixTransformerReadError(t *testing.T) {
	cases := []struct {
		name      string
		prefix    string
		input     []byte
		innerErr  error
		expectErr bool
	}{
		{
			name:      "matching prefix with inner error",
			prefix:    "enc:",
			input:     []byte("enc:corrupted"),
			innerErr:  fmt.Errorf("hmac verification failed"),
			expectErr: true,
		},
		{
			name:      "matching prefix no error",
			prefix:    "enc:",
			input:     []byte("enc:valid"),
			innerErr:  nil,
			expectErr: false,
		},
		{
			name:      "unmatched prefix",
			prefix:    "enc:",
			input:     []byte("other:valid"),
			innerErr:  nil,
			expectErr: true, // default error from NewPrefixTransformers
		},
	}

	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			pt := NewPrefixTransformers(
				fmt.Errorf("no match"),
				PrefixTransformer{
					Prefix:      []byte(tc.prefix),
					Transformer: &mockTransformer{fromResult: []byte("ok"), fromErr: tc.innerErr},
				},
			)
			ctx := testReqCtx()

			_, _, err := pt.TransformFromStorage(ctx, tc.input, nil)
			if tc.expectErr && err == nil {
				t.Error("TransformFromStorage() expected error, got nil")
			}
			if !tc.expectErr && err != nil {
				t.Errorf("TransformFromStorage() unexpected error: %v", err)
			}
		})
	}
}

// TestPrefixTransformerPrefixStripping verifies that the prefix bytes are stripped from
// the data before handing it to the inner transformer.
func TestPrefixTransformerPrefixStripping(t *testing.T) {
	inner := &mockTransformer{fromResult: []byte("plain")}
	prefix := []byte("k8s:enc:aescbc:v1:")
	pt := NewPrefixTransformers(
		fmt.Errorf("no match"),
		PrefixTransformer{Prefix: prefix, Transformer: inner},
	)
	ctx := testReqCtx()

	payload := []byte("ciphertext")
	fullData := append(append([]byte{}, prefix...), payload...)

	_, _, err := pt.TransformFromStorage(ctx, fullData, nil)
	if err != nil {
		t.Fatalf("TransformFromStorage() unexpected error: %v", err)
	}
	if !bytes.Equal(inner.lastFromInput, payload) {
		t.Errorf("inner transformer received %q, want prefix-stripped %q", inner.lastFromInput, payload)
	}
}

// TestPrefixTransformerOverlappingPrefixes verifies that when multiple transformers share
// the same prefix but the first fails, the next matching transformer is tried.
func TestPrefixTransformerOverlappingPrefixes(t *testing.T) {
	firstErr := fmt.Errorf("wrong key")
	first := &mockTransformer{fromErr: firstErr}
	second := &mockTransformer{fromResult: []byte("decrypted with key2")}

	sharedPrefix := []byte("k8s:enc:aescbc:v1:")
	pt := NewPrefixTransformers(
		fmt.Errorf("no match"),
		PrefixTransformer{Prefix: sharedPrefix, Transformer: first},
		PrefixTransformer{Prefix: sharedPrefix, Transformer: second},
	)
	ctx := testReqCtx()

	got, stale, err := pt.TransformFromStorage(ctx, append(append([]byte{}, sharedPrefix...), []byte("data")...), nil)
	if err != nil {
		t.Fatalf("TransformFromStorage() unexpected error: %v", err)
	}
	if !stale {
		t.Error("TransformFromStorage() stale = false, want true: data matched non-primary transformer")
	}
	if !bytes.Equal(got, []byte("decrypted with key2")) {
		t.Errorf("TransformFromStorage() = %q, want %q", got, []byte("decrypted with key2"))
	}
}

